import (
	"context"
	"fmt"

	entdb "github.com/openmeterio/openmeter/openmeter/ent/db"
	taxcodedb "github.com/openmeterio/openmeter/openmeter/ent/db/taxcode"
	"github.com/openmeterio/openmeter/openmeter/taxcode"
	"github.com/openmeterio/openmeter/pkg/framework/entutils"
)

func (a *adapter) ArchiveTaxCode(ctx context.Context, input taxcode.ArchiveTaxCodeInput) (taxcode.TaxCode, error) {
	if err := input.Validate(); err != nil {
		return taxcode.TaxCode{}, err
	}
	return entutils.TransactingRepo(ctx, a, func(ctx context.Context, a *adapter) (taxcode.TaxCode, error) {
		entity, err := a.db.TaxCode.UpdateOneID(input.ID).
			Where(taxcodedb.NamespaceEQ(input.Namespace)).
			Where(taxcodedb.DeletedAtIsNil()).
			SetArchivedAt(clock.Now()).
			Save(ctx)
		if err != nil {
			if entdb.IsNotFound(err) {
				return taxcode.TaxCode{}, taxcode.NewTaxCodeNotFoundError(input.ID)
			}
			return taxcode.TaxCode{}, fmt.Errorf("failed to archive tax code: %w", err)
		}
		return MapTaxCodeFromEntity(entity)
	})
}

func (s *Service) PatchTaxCode(ctx context.Context, input taxcode.PatchTaxCodeInput) (taxcode.TaxCode, error) {
	if err := input.Validate(); err != nil {
		return taxcode.TaxCode{}, err
	}
	return transaction.Run(ctx, s.adapter, func(ctx context.Context) (taxcode.TaxCode, error) {
		existing, err := s.adapter.GetTaxCode(ctx, taxcode.GetTaxCodeInput{NamespacedID: input.NamespacedID})
		if err != nil {
			return taxcode.TaxCode{}, err
		}
		if existing.IsManagedBySystem() && !input.AllowAnnotations {
			return taxcode.TaxCode{}, models.NewGenericConflictError(taxcode.ErrTaxCodeManagedBySystem)
		}
		return s.adapter.PatchTaxCode(ctx, input)
	})
}
